<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Canvas Billiards</title>
<style>
  :root {
    color-scheme: dark;
    --wood: #6b3518;
    --felt: #167548;
    --gold: #d8b36a;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: grid;
    place-items: center;
    background:
      radial-gradient(circle at 50% 15%, #2d3948 0, #111820 52%, #080b0e 100%);
    font-family: Arial, Helvetica, sans-serif;
    color: #f5ead0;
  }
  .game {
    width: min(960px, 96vw);
    padding: 16px;
    border: 1px solid #65461f;
    border-radius: 18px;
    background: linear-gradient(145deg, #302113, #17100b);
    box-shadow: 0 18px 60px #000b, inset 0 1px #ffffff18;
  }
  header {
    display: flex;
    gap: 14px;
    justify-content: space-between;
    align-items: center;
    margin: 0 2px 12px;
  }
  h1 {
    font-family: Georgia, serif;
    font-size: clamp(1.25rem, 3vw, 1.8rem);
    letter-spacing: .08em;
    margin: 0;
    color: #f3d58a;
    text-shadow: 0 2px 2px #000;
  }
  button {
    border: 1px solid #f2cb76;
    border-radius: 7px;
    padding: 8px 13px;
    color: #2b180a;
    font-weight: bold;
    cursor: pointer;
    background: linear-gradient(#ffe0a0, #bd833d);
    box-shadow: 0 2px 3px #0009;
  }
  button:hover { filter: brightness(1.12); }
  canvas {
    display: block;
    width: 100%;
    height: auto;
    border-radius: 10px;
    background: #166e43;
    box-shadow: 0 0 0 2px #0a0805, 0 8px 20px #000b;
    touch-action: none;
  }
  .instructions {
    margin: 12px 4px 2px;
    text-align: center;
    line-height: 1.45;
    color: #eadbbd;
    font-size: .95rem;
  }
  .instructions strong { color: #ffe098; }
  #status {
    display: inline-block;
    margin-left: .35em;
    color: #aee6c0;
    font-weight: bold;
  }
</style>
</head>
<body>
<div class="game">
  <header>
    <h1>CANVAS BILLIARDS</h1>
    <button id="rack" type="button">Reset / Rack</button>
  </header>
  <canvas id="table" width="900" height="500" aria-label="Playable billiards table"></canvas>
  <div class="instructions">
    <strong>How to shoot:</strong> press the white cue ball, drag backward to aim and set power, then release.
    <span id="status"></span>
  </div>
</div>

<script>
(() => {
  "use strict";

  const canvas = document.getElementById("table");
  const ctx = canvas.getContext("2d");
  const rackButton = document.getElementById("rack");
  const status = document.getElementById("status");

  const W = 900;
  const H = 500;
  const R = 12;
  const POCKET_RADIUS = R * 1.8;
  const FRICTION = 55;           // pixels/sec²
  const WALL_RESTITUTION = 0.98;
  const BALL_RESTITUTION = 1.0;
  const MAX_SUBSTEP = 1 / 240;

  let balls = [];
  let running = true;
  let frameHandle = 0;
  let previousTime = performance.now();
  let drag = null;

  const pocketCenters = [
    { x: 0, y: 0 }, { x: W / 2, y: 0 }, { x: W, y: 0 },
    { x: 0, y: H }, { x: W / 2, y: H }, { x: W, y: H }
  ];

  const ballColors = [
    "#ffffff", "#e9c51e", "#276ec6", "#c82d30", "#6b3b90",
    "#e67c24", "#1b8c57", "#7d1d20", "#171717", "#f0cf20",
    "#2b6fc3", "#c72d35", "#704098", "#e97826", "#198353", "#78202a"
  ];

  function speed(ball) {
    return Math.hypot(ball.vx, ball.vy);
  }

  function cueBall() {
    return balls.find(b => b.cue && !b.potted) || null;
  }

  function isInPocket(ball) {
    for (const p of pocketCenters) {
      const dx = ball.x - p.x;
      const dy = ball.y - p.y;
      if (dx * dx + dy * dy <= POCKET_RADIUS * POCKET_RADIUS) return true;
    }
    return false;
  }

  function cushion(ball) {
    if (isInPocket(ball)) {
      ball.potted = true;
      ball.vx = 0;
      ball.vy = 0;
      return;
    }

    if (ball.x < R) {
      ball.x = R;
      if (ball.vx < 0) ball.vx = -ball.vx * WALL_RESTITUTION;
    } else if (ball.x > W - R) {
      ball.x = W - R;
      if (ball.vx > 0) ball.vx = -ball.vx * WALL_RESTITUTION;
    }

    if (ball.y < R) {
      ball.y = R;
      if (ball.vy < 0) ball.vy = -ball.vy * WALL_RESTITUTION;
    } else if (ball.y > H - R) {
      ball.y = H - R;
      if (ball.vy > 0) ball.vy = -ball.vy * WALL_RESTITUTION;
    }

    if (isInPocket(ball)) {
      ball.potted = true;
      ball.vx = 0;
      ball.vy = 0;
    }
  }

  function collide(a, b, ai, bi) {
    if (a.potted || b.potted) return;

    let dx = b.x - a.x;
    let dy = b.y - a.y;
    let d2 = dx * dx + dy * dy;
    const minD = R * 2;

    if (d2 >= minD * minD) return;

    let d = Math.sqrt(d2);
    let nx, ny;
    if (d < 0.000001) {
      const angle = ((ai + 1) * 17 + (bi + 1) * 31) * 0.71;
      nx = Math.cos(angle);
      ny = Math.sin(angle);
      d = 0;
    } else {
      nx = dx / d;
      ny = dy / d;
    }

    // Separate overlapping equal-size balls evenly.
    const overlap = minD - d;
    if (overlap > 0) {
      const correction = overlap * 0.5 + 0.00001;
      a.x -= nx * correction;
      a.y -= ny * correction;
      b.x += nx * correction;
      b.y += ny * correction;
    }

    // Equal mass elastic impulse along the centre line.
    const relativeNormalVelocity = (b.vx - a.vx) * nx + (b.vy - a.vy) * ny;
    if (relativeNormalVelocity < 0) {
      const impulse = -(1 + BALL_RESTITUTION) * relativeNormalVelocity / 2;
      a.vx -= impulse * nx;
      a.vy -= impulse * ny;
      b.vx += impulse * nx;
      b.vy += impulse * ny;
    }
  }

  function applyFriction(ball, dt) {
    const s = speed(ball);
    if (s <= 0) return;
    const newSpeed = Math.max(0, s - FRICTION * dt);
    if (newSpeed < 0.45) {
      ball.vx = 0;
      ball.vy = 0;
    } else {
      const ratio = newSpeed / s;
      ball.vx *= ratio;
      ball.vy *= ratio;
    }
  }

  function physicsSubstep(dt) {
    for (const b of balls) {
      if (b.potted) continue;
      b.x += b.vx * dt;
      b.y += b.vy * dt;
      cushion(b);
    }

    // A few deterministic passes keep clusters stable without adding energy.
    for (let pass = 0; pass < 2; pass++) {
      for (let i = 0; i < balls.length; i++) {
        for (let j = i + 1; j < balls.length; j++) {
          collide(balls[i], balls[j], i, j);
        }
      }
    }

    for (const b of balls) {
      if (b.potted) continue;
      cushion(b);
      if (!b.potted) applyFriction(b, dt);
    }
  }

  function advance(dt) {
    if (!Number.isFinite(dt) || dt <= 0) {
      draw();
      return;
    }

    let remaining = dt;
    while (remaining > 0) {
      let maximumSpeed = 0;
      for (const b of balls) {
        if (!b.potted) maximumSpeed = Math.max(maximumSpeed, speed(b));
      }
      const movementLimitedStep = maximumSpeed > 0
        ? (R * 0.35) / maximumSpeed
        : MAX_SUBSTEP;
      const h = Math.min(remaining, MAX_SUBSTEP, movementLimitedStep);
      physicsSubstep(h);
      remaining -= h;
    }
    draw();
  }

  function setBalls(input) {
    balls = (Array.isArray(input) ? input : []).map((b, index) => ({
      x: Number.isFinite(b.x) ? b.x : W / 2,
      y: Number.isFinite(b.y) ? b.y : H / 2,
      vx: Number.isFinite(b.vx) ? b.vx : 0,
      vy: Number.isFinite(b.vy) ? b.vy : 0,
      cue: b.cue === true,
      potted: false,
      colorIndex: index
    }));
    drag = null;
    draw();
  }

  function currentState() {
    return balls.map(b => ({
      x: b.x,
      y: b.y,
      vx: b.vx,
      vy: b.vy,
      potted: b.potted,
      cue: b.cue
    }));
  }

  function shoot(vx, vy) {
    const cue = cueBall();
    if (!cue) return;
    cue.vx = Number.isFinite(vx) ? vx : 0;
    cue.vy = Number.isFinite(vy) ? vy : 0;
    draw();
  }

  function drawPocket(x, y) {
    ctx.beginPath();
    ctx.arc(x, y, 23, 0, Math.PI * 2);
    ctx.fillStyle = "#080a08";
    ctx.fill();
    ctx.beginPath();
    ctx.arc(x, y, 17, 0, Math.PI * 2);
    ctx.fillStyle = "#020302";
    ctx.fill();
  }

  function drawBall(b) {
    if (b.potted) return;
    const color = b.cue ? "#f8f8ef" : ballColors[(b.colorIndex % 15) + 1] || "#e5b91b";

    ctx.save();
    ctx.beginPath();
    ctx.arc(b.x + 2, b.y + 3, R + 1, 0, Math.PI * 2);
    ctx.fillStyle = "#00000055";
    ctx.fill();

    const gradient = ctx.createRadialGradient(
      b.x - R * 0.35, b.y - R * 0.45, R * 0.12,
      b.x, b.y, R * 1.15
    );
    gradient.addColorStop(0, "#ffffff");
    gradient.addColorStop(0.14, color);
    gradient.addColorStop(0.76, color);
    gradient.addColorStop(1, "#101010");
    ctx.beginPath();
    ctx.arc(b.x, b.y, R, 0, Math.PI * 2);
    ctx.fillStyle = gradient;
    ctx.fill();

    if (!b.cue && b.colorIndex > 7) {
      ctx.save();
      ctx.beginPath();
      ctx.arc(b.x, b.y, R * 0.56, 0, Math.PI * 2);
      ctx.fillStyle = "#f4ead8";
      ctx.fill();
      ctx.fillStyle = "#222";
      ctx.font = "bold 9px Arial";
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(String(b.colorIndex), b.x, b.y + .5);
      ctx.restore();
    }
    ctx.restore();
  }

  function drawAim() {
    if (!drag) return;
    const cue = cueBall();
    if (!cue) return;

    const dx = cue.x - drag.x;
    const dy = cue.y - drag.y;
    const length = Math.hypot(dx, dy);
    if (length < 1) return;

    const ux = dx / length;
    const uy = dy / length;
    const power = Math.min(1, length / 180);

    ctx.save();
    ctx.setLineDash([8, 6]);
    ctx.lineWidth = 2;
    ctx.strokeStyle = "rgba(255, 231, 162, .9)";
    ctx.beginPath();
    ctx.moveTo(cue.x, cue.y);
    ctx.lineTo(drag.x, drag.y);
    ctx.stroke();

    ctx.setLineDash([5, 7]);
    ctx.strokeStyle = `rgba(255,255,255,${0.35 + power * 0.55})`;
    ctx.beginPath();
    ctx.moveTo(cue.x, cue.y);
    ctx.lineTo(cue.x + ux * (95 + power * 115), cue.y + uy * (95 + power * 115));
    ctx.stroke();

    ctx.setLineDash([]);
    ctx.fillStyle = "#ffe7a4";
    ctx.fillRect(18, H - 27, 150, 9);
    ctx.fillStyle = "#cc712a";
    ctx.fillRect(18, H - 27, 150 * power, 9);
    ctx.strokeStyle = "#3c1d0b";
    ctx.strokeRect(18, H - 27, 150, 9);
    ctx.restore();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    ctx.fillStyle = "#673516";
    ctx.fillRect(0, 0, W, H);
    ctx.fillStyle = "#9b6128";
    ctx.fillRect(8, 8, W - 16, H - 16);

    ctx.fillStyle = "#0d5634";
    ctx.fillRect(15, 15, W - 30, H - 30);
    const felt = ctx.createLinearGradient(0, 0, W, H);
    felt.addColorStop(0, "#237e51");
    felt.addColorStop(.55, "#14663e");
    felt.addColorStop(1, "#0d5534");
    ctx.fillStyle = felt;
    ctx.fillRect(18, 18, W - 36, H - 36);

    ctx.strokeStyle = "rgba(255,255,255,.10)";
    ctx.lineWidth = 1;
    ctx.strokeRect(18.5, 18.5, W - 37, H - 37);

    for (const p of pocketCenters) drawPocket(p.x, p.y);
    drawAim();
    for (const b of balls) drawBall(b);

    const pottedCount = balls.filter(b => b.potted && !b.cue).length;
    status.textContent = `${pottedCount} ball${pottedCount === 1 ? "" : "s"} potted`;
  }

  function eventPosition(event) {
    const rect = canvas.getBoundingClientRect();
    return {
      x: (event.clientX - rect.left) * W / rect.width,
      y: (event.clientY - rect.top) * H / rect.height
    };
  }

  canvas.addEventListener("pointerdown", event => {
    const cue = cueBall();
    if (!cue || speed(cue) > 0.5) return;
    const p = eventPosition(event);
    if (Math.hypot(p.x - cue.x, p.y - cue.y) <= R * 1.8) {
      drag = p;
      canvas.setPointerCapture(event.pointerId);
      draw();
      event.preventDefault();
    }
  });

  canvas.addEventListener("pointermove", event => {
    if (!drag) return;
    drag = eventPosition(event);
    draw();
  });

  function releaseShot(event) {
    if (!drag) return;
    const cue = cueBall();
    const p = eventPosition(event);
    if (cue) {
      const dx = cue.x - p.x;
      const dy = cue.y - p.y;
      const length = Math.hypot(dx, dy);
      if (length > 2) {
        const capped = Math.min(length, 220);
        shoot(dx / length * capped * 5, dy / length * capped * 5);
      }
    }
    drag = null;
    draw();
  }

  canvas.addEventListener("pointerup", releaseShot);
  canvas.addEventListener("pointercancel", () => {
    drag = null;
    draw();
  });

  function makeRack() {
    const layout = [{ x: W * 0.23, y: H / 2, vx: 0, vy: 0, cue: true }];
    const apexX = W * 0.68;
    let n = 1;
    for (let row = 0; row < 5; row++) {
      for (let col = 0; col <= row; col++) {
        layout.push({
          x: apexX + row * Math.sqrt(3) * R,
          y: H / 2 + (col - row / 2) * R * 2.04,
          vx: 0,
          vy: 0,
          cue: false
        });
        n++;
      }
    }
    return layout;
  }

  rackButton.addEventListener("click", () => setBalls(makeRack()));

  function animationFrame(now) {
    if (!running) return;
    const elapsed = Math.min((now - previousTime) / 1000, 0.05);
    previousTime = now;
    advance(elapsed);
    frameHandle = requestAnimationFrame(animationFrame);
  }

  window.sim = {
    W,
    H,
    R,
    reset: setBalls,
    step: advance,
    state: currentState,
    shoot,
    pause() {
      running = false;
      if (frameHandle) cancelAnimationFrame(frameHandle);
      frameHandle = 0;
    },
    resume() {
      if (running) return;
      running = true;
      previousTime = performance.now();
      frameHandle = requestAnimationFrame(animationFrame);
    }
  };

  setBalls(makeRack());
  frameHandle = requestAnimationFrame(animationFrame);
})();
</script>
</body>
</html>
